sys_variable_value.value:
(function execute(inputs, outputs) {
    
    var gdt = new GlideDateTime();
    
    gdt.addDaysLocalTime(inputs.days_from_now);
    outputs.fulfillment_date=gdt;

    
})(inputs, outputs);

